def init_saml_auth(req):
    """Initializes a OneLogin_Saml2_Auth object."""
    # `old_auth` is used to maintain state across redirects if necessary (e.g., for RelayState)
    return OneLogin_Saml2_Auth(req, old_auth=session.get('samlAuth'))

def prepare_flask_request(request):
    """
    Prepares the Flask request object into a format suitable for the python3-saml library.
    """
    return {
        'http_host': request.host,
        'server_port': request.port,
        'script_name': request.path,
        'get_data': request.args.copy(),
        'post_data': request.form.copy(),
        'query_string': request.query_string.decode('utf-8'),
        'https': 'on' if request.scheme == 'https' else 'off',
        'security': ONELOGIN_SAML_SETTINGS['security']
    }

