@app.route('/saml/sso', methods=['GET'])
def saml_sso():
    """
    IdP's Single Sign-On (SSO) endpoint.
    This endpoint receives SAML Authentication Requests from Service Providers.
    It simulates user authentication and issues a SAML Response.
    """
    req = prepare_flask_request(request)
    auth = init_saml_auth(req)

    try:
        # Process the incoming SAMLRequest (sent by the SP)
        # This parses the request and populates the auth object with SP details.
        auth.process_saml_request()
        errors = auth.get_errors()

        if errors:
            app.logger.error(f"SAML request processing error: {', '.join(errors)}")
            return f"Error processing SAML request: {', '.join(errors)}", 400
        
        if not auth.is_authenticated():
            # This check validates if the SAMLRequest was successfully processed
            # and if the SP is known and configured correctly according to IdP settings.
            # If false, it means the request might be invalid or from an unknown SP.
            return "SP not authenticated or SAML request invalid.", 403

        # Simulate successful user authentication
        # In a real IdP, this is where a user would log in (e.g., via a form, LDAP, etc.)
        # For this example, we'll hardcode user data.
        name_id = 'testuser@example.com'
        name_id_format = 'urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress' # Common format

        attributes = {
            'uid': ['testuser'],
            'email': ['testuser@example.com'],
            'memberOf': ['users', 'everyone'],
            'firstName': ['Test'],
            'lastName': ['User']
        }

        # A unique identifier for the user's session at the IdP, used for Single Logout (SLO).
        # For SSO, a simple unique ID is sufficient.
        session_index = OneLogin_Saml2_Utils.generate_unique_id()

        # The SP's Assertion Consumer Service (ACS) URL, where the SAML Response will be sent.
        acs_url = auth.get_assertion_consumer_service_url()
        if not acs_url:
            return "Could not determine SP's Assertion Consumer Service URL.", 400

        # Build the SAML response.
        # The library automatically signs assertions if 'security']['signAssertions'] is True
        # and does not encrypt if 'security']['encryptAssertions'] is False, as configured.
        saml_response = auth.build_auth_response(
            name_id=name_id,
            attributes=attributes,
            name_id_format=name_id_format,
            session_index=session_index,
            sso_redirect_url=acs_url # The target URL for the POST
        )

        # The SAML response must be base64 encoded for HTTP-POST binding.
        encoded_saml_response = OneLogin_Saml2_Utils.b64encode_to_string(saml_response)

        # Send the SAMLResponse back to the SP using HTTP-POST binding.
        # This involves rendering an HTML form that automatically submits the response to the ACS URL.
        return render_template_string(POST_TEMPLATE, acs_url=acs_url, saml_response=encoded_saml_response)

    except Exception as e:
        app.logger.error(f"SAML SSO Error: {e}")
        return f"An internal error occurred during SSO: {e}", 500

@app.route('/saml/metadata')
def saml_metadata():
    """
    Provides the IdP's metadata XML.
    Service Providers consume this to configure themselves against this IdP.
    """
    saml_settings = OneLogin_Saml2_Settings(ONELOGIN_SAML_SETTINGS)
    metadata = saml_settings.get_idp_metadata()
    errors = saml_settings.validate_metadata(metadata)
    if len(errors) > 0:
        app.logger.error(f"Invalid IdP metadata: {', '.join(errors)}")
        return f"Invalid IdP metadata: {', '.join(errors)}", 500

    response = app.make_response(metadata)
    response.headers['Content-Type'] = 'text/xml'
    return response

